from __future__ import annotations

# AUTO-GENERATED MATCHER SHIM (REQ-003-007)
# Matcher: Bash
# Generated by build/scripts/generate_hooks.py (REQ-003-007).
# DO NOT EDIT BY HAND - regenerated on every build. Apply NO-REGEN
# sentinel ("# NO-REGEN" or sidecar .noregen) to opt out.
import os as _os
import sys as _sys
import io as _io
import json as _json
import re as _re
import fnmatch as _fnmatch

_MATCHER = 'Bash'

# Cap stdin read so a malicious or buggy upstream cannot OOM the shim
# (CWE-400). Mirrors push_guard_base.MAX_STDIN_BYTES (1 MiB) with a
# small headroom; real Claude/Copilot tool_input commands are well
# below this limit. The cap belongs at the SHIM layer because the
# shim reads stdin BEFORE delegating to the wrapped script. Without
# it, the wrapped script's own cap is applied too late: the OOM has
# already happened.
_SHIM_MAX_STDIN_BYTES = 2 * 1024 * 1024


def _shim_classify(pattern):
    # MIRROR: classify_matcher (build-time, build/scripts/generate_hooks.py)
    # and _shim_classify (runtime, this inlined copy) MUST agree on the
    # grammar. Update both when the grammar changes.
    if pattern.startswith("^") and pattern.endswith("$"):
        return "regex", {"pattern": pattern}
    m = _re.match(r"^([A-Za-z_][A-Za-z0-9_]*)\((.*)\)$", pattern)
    if m:
        return "tool-glob", {"toolName": m.group(1), "argsGlob": m.group(2)}
    return "bare", {"toolName": pattern}


def _shim_normalize_args(tool_args):
    r"""Stringify and whitespace-normalize tool_input for fnmatch comparison.

    REQ-003-007: collapse \s+ to a single space and strip ends. Pattern
    is NOT normalized; authors write patterns assuming single spaces.
    """
    if isinstance(tool_args, dict):
        # Bash hooks place command under "command"; keep this fallback
        # path narrow but correct for the live corpus.
        cmd = tool_args.get("command")
        if isinstance(cmd, str):
            text = cmd
        else:
            text = _json.dumps(tool_args, sort_keys=True)
    elif isinstance(tool_args, str):
        text = tool_args
    elif tool_args is None:
        text = ""
    else:
        text = str(tool_args)
    return _re.sub(r"\s+", " ", text).strip()


def _shim_glob_match(args_glob, tool_args_norm):
    """Match args_glob against tool_args_norm with `|` as alternation.

    fnmatch treats `|` as a literal. Authors expect Claude semantics
    where each `|` branch is a separate glob alternation. Split on
    top-level `|` and OR-fold the results.
    """
    branches = args_glob.split("|") if args_glob else [""]
    for branch in branches:
        if _fnmatch.fnmatchcase(tool_args_norm, branch):
            return True
    return False


def _shim_should_fire(payload):
    kind, params = _shim_classify(_MATCHER)
    # Support both VS Code-compatible snake_case (PascalCase event names)
    # and native camelCase (camelCase event names) payloads.
    # Copilot CLI sends snake_case when the event key is PascalCase,
    # camelCase when the event key is camelCase. See issue #2290.
    tool_name = payload.get("tool_name")
    if tool_name is None:
        tool_name = payload.get("toolName")
    if not isinstance(tool_name, str):
        raise ValueError("hook input missing string `tool_name`/`toolName` field")
    if kind == "regex":
        return _re.fullmatch(params["pattern"], tool_name) is not None
    if kind == "tool-glob":
        if tool_name != params["toolName"]:
            return False
        tool_args = payload.get("tool_input")
        if tool_args is None:
            tool_args = payload.get("toolArgs")
        # camelCase payloads send toolArgs as a JSON string, not a parsed
        # object. Parse it so _shim_normalize_args can extract "command".
        if isinstance(tool_args, str):
            try:
                tool_args = _json.loads(tool_args)
            except ValueError as exc:
                # Host sent a string that is not valid JSON. Log so
                # the operator can diagnose; fall through to normalize
                # which treats raw strings as-is (glob may not match).
                print(
                    "matcher-shim [{}]: toolArgs is not valid JSON: {}".format(
                        _MATCHER, exc
                    ),
                    file=_sys.stderr,
                )
        norm_args = _shim_normalize_args(tool_args)
        return _shim_glob_match(params["argsGlob"], norm_args)
    # bare
    return tool_name == params["toolName"]


def _shim_replay_bytes(payload, raw):
    replay = dict(payload)
    changed = False
    tool_name = replay.get("tool_name")
    if tool_name is None and isinstance(replay.get("toolName"), str):
        replay["tool_name"] = replay["toolName"]
        changed = True
    tool_input = replay.get("tool_input")
    if tool_input is None and "toolArgs" in replay:
        tool_args = replay.get("toolArgs")
        if isinstance(tool_args, str):
            try:
                tool_args = _json.loads(tool_args)
            except ValueError:
                pass
        replay["tool_input"] = tool_args
        changed = True
    if not changed:
        return raw
    return _json.dumps(replay, separators=(",", ":")).encode("utf-8")


def _shim_dispatch():
    try:
        _raw = _sys.stdin.buffer.read(_SHIM_MAX_STDIN_BYTES + 1)
    except Exception as exc:  # pragma: no cover - defensive
        print(
            "matcher-shim [{}]: failed to buffer stdin: {}".format(_MATCHER, exc),
            file=_sys.stderr,
        )
        _sys.exit(2)
    if len(_raw) > _SHIM_MAX_STDIN_BYTES:
        print(
            "matcher-shim [{}]: stdin exceeds {} bytes; refusing".format(
                _MATCHER, _SHIM_MAX_STDIN_BYTES
            ),
            file=_sys.stderr,
        )
        _sys.exit(2)
    try:
        payload = _json.loads(_raw or b"{}")
    except _json.JSONDecodeError as exc:
        print(
            "matcher-shim [{}]: malformed JSON on stdin: {}".format(_MATCHER, exc),
            file=_sys.stderr,
        )
        _sys.exit(2)
    try:
        fire = _shim_should_fire(payload)
    except Exception as exc:
        print(
            "matcher-shim [{}]: dispatch error: {}".format(_MATCHER, exc),
            file=_sys.stderr,
        )
        _sys.exit(2)
    if _os.environ.get("COPILOT_HOOK_DEBUG"):
        kind, _ = _shim_classify(_MATCHER)
        _sys.stderr.write(
            "matcher-shim [{}]: kind={} fired={}\n".format(_MATCHER, kind, fire)
        )
    if not fire:
        _sys.exit(0)
    # Replay a canonical payload into a fresh stdin so wrapped hooks enforce
    # the same schema even when the host sent the camelCase variant.
    _replay = _shim_replay_bytes(payload, _raw)
    _sys.stdin = _io.TextIOWrapper(_io.BytesIO(_replay), encoding="utf-8")
    rc = _original_main(_replay)
    if rc is None:
        rc = 0
    _sys.exit(int(rc))


# END MATCHER SHIM

def _original_main(stdin_bytes):
    # original script body begins below
    #!/usr/bin/env python3
    """Surface relevant correction memories before Bash command execution.

    Implements the 'Apply' step of the Self-Improving Agent pattern (issue #1345).
    Scans .serena/memories/ for HIGH confidence corrections and surfaces matches
    before the agent repeats a known mistake.

    The Detect-Log-Graduate-Apply loop:
    1. Detect: reflect skill + Stop hook (invoke_skill_learning.py)
    2. Log: Serena observation memories
    3. Graduate: skillbook agent promotes patterns
    4. Apply: THIS HOOK surfaces corrections at command time

    Hook Type: PreToolUse
    Exit Codes (Claude Hook Semantics, exempt from ADR-035):
        0 = Allow (always, this is advisory only)
    """


    import json
    import os
    import re
    import sys
    from pathlib import Path

    # Bootstrap: find lib directory via env var or manifest walk-up.
    # CLAUDE_PLUGIN_ROOT honored when set; otherwise walk up from __file__
    # looking for .claude-plugin/plugin.json (the plugin marker). Sibling
    # lib/ is the plugin's lib dir. Layout-independent: works in source
    # tree (.claude/) and in the deeper src/<provider>/hooks/<event>/ copy.
    _plugin_root = os.environ.get("CLAUDE_PLUGIN_ROOT")
    if _plugin_root:
        _lib_dir = str(Path(_plugin_root).resolve() / "lib")
    else:
        _cur = Path(__file__).resolve().parent
        _lib_dir = None
        while True:
            if (_cur / ".claude-plugin" / "plugin.json").is_file():
                _lib_dir = str(_cur / "lib")
                break
            if _cur.parent == _cur:
                break
            _cur = _cur.parent
    if _lib_dir is None or not os.path.isdir(_lib_dir):
        print(f"Plugin lib directory not found: {_lib_dir} (CLAUDE_PLUGIN_ROOT={_plugin_root!r})", file=sys.stderr)
        # Non-blocking hook: exit 0 on bootstrap failure (intentional, not a typo)
        sys.exit(0)
    if _lib_dir not in sys.path:
        sys.path.insert(0, _lib_dir)  # Fail open when lib not found

    try:
        from hook_utilities import get_project_directory
        from hook_utilities.guards import skip_if_consumer_repo
    except ImportError:

        def get_project_directory() -> str:
            env_dir = os.environ.get("CLAUDE_PROJECT_DIR", "").strip()
            if env_dir:
                return str(Path(env_dir).resolve())
            return str(Path.cwd())

        def skip_if_consumer_repo(hook_name: str) -> bool:
            agents_path = Path(get_project_directory()) / ".agents"
            if not agents_path.is_dir():
                print(f"[SKIP] {hook_name}: .agents/ not found", file=sys.stderr)
                return True
            return False


    # Section header pattern for HIGH confidence corrections
    _HIGH_SECTION_RE = re.compile(
        r"^##\s+Constraints\s+\(HIGH\s+confidence\)",
        re.IGNORECASE,
    )
    # Any markdown heading (used to detect section boundaries)
    _HEADING_RE = re.compile(r"^##\s+")
    # Maximum corrections to surface per invocation (avoid context bloat)
    MAX_CORRECTIONS = 3
    # Minimum keyword length to avoid false positives
    MIN_KEYWORD_LENGTH = 4


    def parse_command(stdin_data: str) -> str | None:
        """Extract the Bash command from hook stdin JSON."""
        try:
            data = json.loads(stdin_data)
        except (json.JSONDecodeError, TypeError):
            return None
        tool_input = data.get("tool_input", {})
        if isinstance(tool_input, str):
            try:
                tool_input = json.loads(tool_input)
            except (json.JSONDecodeError, TypeError):
                return tool_input
        return tool_input.get("command") if isinstance(tool_input, dict) else None


    def extract_high_corrections(content: str) -> list[str]:
        """Extract bullet points from the Constraints (HIGH confidence) section."""
        lines = content.splitlines()
        in_high_section = False
        corrections: list[str] = []
        current_bullet: list[str] = []

        for line in lines:
            if _HIGH_SECTION_RE.match(line):
                in_high_section = True
                continue
            if in_high_section and _HEADING_RE.match(line):
                break
            if in_high_section:
                stripped = line.strip()
                if stripped.startswith("- "):
                    if current_bullet:
                        corrections.append(" ".join(current_bullet))
                    current_bullet = [stripped[2:]]
                elif stripped and current_bullet:
                    current_bullet.append(stripped)

        if current_bullet:
            corrections.append(" ".join(current_bullet))

        return corrections


    def extract_keywords(command: str) -> list[str]:
        """Extract meaningful keywords from a Bash command."""
        tokens = re.split(r"[\s|;&]+", command)
        keywords: list[str] = []
        for token in tokens:
            if token.lstrip("'\"").startswith("-"):
                continue
            clean = token.strip("'-\"./\\")
            if len(clean) < MIN_KEYWORD_LENGTH:
                continue
            keywords.append(clean.lower())
        return keywords


    def find_matching_corrections(
        corrections: list[tuple[str, str]],
        keywords: list[str],
    ) -> list[tuple[str, str]]:
        """Find corrections whose text matches any command keyword.

        Returns list of (source_file, correction_text) tuples.
        """
        matches: list[tuple[str, str]] = []
        for source, text in corrections:
            text_lower = text.lower()
            for kw in keywords:
                if kw in text_lower:
                    matches.append((source, text))
                    break
        return matches


    def scan_memories(project_root: str) -> list[tuple[str, str]]:
        """Scan .serena/memories/ for HIGH confidence corrections.

        Returns list of (source_file, correction_text) tuples.
        """
        memories_dir = Path(project_root) / ".serena" / "memories"
        if not memories_dir.is_dir():
            return []

        all_corrections: list[tuple[str, str]] = []

        for md_file in memories_dir.rglob("*.md"):
            try:
                content = md_file.read_text(encoding="utf-8")
            except (OSError, UnicodeDecodeError):
                continue
            corrections = extract_high_corrections(content)
            for c in corrections:
                all_corrections.append((md_file.name, c))

        return all_corrections


    def main() -> int:
        """Main entry point. Always returns 0 (advisory, never blocks)."""
        hook_name = "correction-applier"
        try:
            if skip_if_consumer_repo(hook_name):
                return 0

            if sys.stdin.isatty():
                return 0

            stdin_data = sys.stdin.read()
            if not stdin_data.strip():
                return 0

            command = parse_command(stdin_data)
            if not command:
                return 0

            keywords = extract_keywords(command)
            if not keywords:
                return 0

            project_root = get_project_directory()
            all_corrections = scan_memories(project_root)
            if not all_corrections:
                return 0

            matches = find_matching_corrections(all_corrections, keywords)
            if not matches:
                return 0

            shown = matches[:MAX_CORRECTIONS]
            lines = ["**Self-Improving Agent: Relevant corrections found**"]
            for source, text in shown:
                lines.append(f"- [{source}] {text}")

            # Advisory hook: surface corrections to the model WITHOUT making a
            # permission decision. PreToolUse model-visible context goes in
            # hookSpecificOutput.additionalContext. {"decision": "allow"} is INVALID:
            # the top-level `decision` field accepts only "approve"/"block" (the
            # blocking guards use "block"); "allow"/"deny"/"ask" belong to
            # hookSpecificOutput.permissionDecision, and setting permissionDecision
            # would auto-approve the tool. additionalContext advises and leaves the
            # normal permission flow intact. The old envelope failed schema
            # validation ("(root): Invalid input"), so the advisory was dropped.
            advisory = "\n".join(lines)
            output = {
                "hookSpecificOutput": {
                    "hookEventName": "PreToolUse",
                    "additionalContext": advisory,
                }
            }
            print(json.dumps(output))
            # Mirror advisory text to stderr for human visibility in logs
            # (stdout must remain valid JSON for the hook protocol).
            print(advisory, file=sys.stderr)
        except Exception as exc:
            print(f"[{hook_name}] Error (fail-open): {exc}", file=sys.stderr)
        return 0
    return main()

_shim_dispatch()
